import { NavLink } from "react-router-dom";
import { useUiStore } from "@/stores/uiStore";
import { useAuthStore } from "@/stores/authStore";

interface NavItem {
  label: string;
  path: string;
  icon: string;
}

const NAV_ITEMS: NavItem[] = [
  { label: "Dashboard", path: "/dashboard", icon: "◈" },
  { label: "Player Cards", path: "/players", icon: "⚔" },
  { label: "Homebrew", path: "/homebrew", icon: "⚗" },
  { label: "Encounters", path: "/encounters", icon: "⚡" },
  { label: "Battle Maps", path: "/maps", icon: "🗺" },
  { label: "Journal", path: "/journal", icon: "📖" },
  { label: "Settings", path: "/settings", icon: "⚙" },
];

export function Sidebar() {
  const sidebarOpen = useUiStore((s) => s.sidebarOpen);
  const toggleSidebar = useUiStore((s) => s.toggleSidebar);
  const username = useAuthStore((s) => s.username);
  const logout = useAuthStore((s) => s.logout);

  return (
    <>
      {/* Mobile Overlay */}
      {sidebarOpen && (
        <div
          className="fixed inset-0 z-20 bg-black/50 md:hidden"
          onClick={toggleSidebar}
          aria-hidden="true"
        />
      )}

      <aside
        className={`fixed left-0 top-0 z-30 flex h-full flex-col border-r border-surface-700 bg-surface-850 transition-all duration-300 md:static md:z-auto ${
          sidebarOpen ? "w-64 translate-x-0" : "w-0 -translate-x-full md:w-16 md:translate-x-0"
        }`}
      >
        {/* Brand */}
        <div className="flex h-14 items-center gap-2 border-b border-surface-700 px-4">
          <span className="text-accent-400 text-xl font-bold">Sᚱ</span>
          {sidebarOpen && (
            <span className="text-sm font-semibold tracking-wide text-surface-200">
              VTT · Arkla
            </span>
          )}
        </div>

        {/* Navigation */}
        <nav className="flex-1 overflow-y-auto py-3">
          {NAV_ITEMS.map((item) => (
            <NavLink
              key={item.path}
              to={item.path}
              onClick={() => {
                // Close sidebar on mobile after navigation
                if (window.innerWidth < 768) toggleSidebar();
              }}
              className={({ isActive }) =>
                `flex items-center gap-3 px-4 py-2.5 text-sm font-medium transition-colors ${
                  isActive
                    ? "border-r-2 border-accent-500 bg-accent-500/10 text-accent-300"
                    : "text-surface-400 hover:bg-surface-800 hover:text-surface-200"
                }`
              }
            >
              <span className="flex h-6 w-6 items-center justify-center text-base">
                {item.icon}
              </span>
              {sidebarOpen && <span>{item.label}</span>}
            </NavLink>
          ))}
        </nav>

        {/* User Info + Logout */}
        <div className="border-t border-surface-700">
          {/* DM Badge */}
          {sidebarOpen && username && (
            <div className="px-4 py-2">
              <div className="flex items-center gap-2 rounded-lg bg-surface-800 px-3 py-2">
                <span className="flex h-6 w-6 items-center justify-center rounded-full bg-accent-500/20 text-xs text-accent-400">
                  👑
                </span>
                <div className="min-w-0 flex-1">
                  <p className="text-xs font-medium text-surface-200 truncate">
                    {username}
                  </p>
                  <p className="text-[10px] text-surface-500">DM</p>
                </div>
              </div>
            </div>
          )}
          <button
            onClick={logout}
            className="flex w-full items-center gap-3 px-4 py-2.5 text-sm font-medium text-surface-400 transition-colors hover:bg-surface-800 hover:text-warrior-400"
          >
            <span className="flex h-6 w-6 items-center justify-center text-base">
              ⟐
            </span>
            {sidebarOpen && <span>Sign Out</span>}
          </button>
        </div>

        {/* Collapse Toggle (Desktop) */}
        <button
          onClick={toggleSidebar}
          className="hidden border-t border-surface-700 p-3 text-surface-500 hover:text-surface-300 md:flex items-center justify-center"
          aria-label={sidebarOpen ? "Collapse sidebar" : "Expand sidebar"}
        >
          <span className={`transition-transform ${sidebarOpen ? "" : "rotate-180"}`}>
            ◀
          </span>
        </button>
      </aside>
    </>
  );
}

