import { useCampaignStore } from "@/stores/campaignStore";
import { Button } from "@/components/ui/Button";

export function PlayerCards() {
  const characters = useCampaignStore((s) => s.campaign?.playerCharacters ?? []);

  return (
    <div className="mx-auto max-w-6xl space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-xl font-bold text-surface-100 md:text-2xl">
            Player Characters
          </h2>
          <p className="mt-1 text-sm text-surface-400">
            Manage your party's heroes ({characters.length} registered)
          </p>
        </div>
        <Button size="sm">+ Add Character</Button>
      </div>

      {characters.length === 0 ? (
        <div className="flex flex-col items-center justify-center rounded-xl border border-dashed border-surface-700 bg-surface-850 py-16">
          <span className="text-4xl text-surface-600">⚔</span>
          <p className="mt-3 text-sm text-surface-500">
            No player characters yet. Add your first hero!
          </p>
        </div>
      ) : (
        <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3">
          {characters.map((char) => (
            <div
              key={char.id}
              className="rounded-xl border border-surface-700 bg-surface-850 p-4 transition-colors hover:border-surface-600"
            >
              <div className="flex items-start justify-between">
                <div>
                  <h3 className="font-semibold text-surface-100">{char.name}</h3>
                  <p className="text-xs text-surface-400">
                    {char.race} · {char.class} Lv.{char.level}
                  </p>
                </div>
                <span className="text-xs text-surface-500">{char.playerName}</span>
              </div>

              {/* HP Bar */}
              <div className="mt-3">
                <div className="flex items-center justify-between text-xs text-surface-400">
                  <span>HP</span>
                  <span>
                    {char.hitPoints.current}/{char.hitPoints.max}
                  </span>
                </div>
                <div className="mt-1 h-2 overflow-hidden rounded-full bg-surface-700">
                  <div
                    className="h-full rounded-full bg-warrior-500 transition-all"
                    style={{
                      width: `${(char.hitPoints.current / char.hitPoints.max) * 100}%`,
                    }}
                  />
                </div>
              </div>

              {/* Ability Scores (Compact) */}
              <div className="mt-3 grid grid-cols-6 gap-1">
                {(
                  [
                    "str",
                    "dex",
                    "con",
                    "int",
                    "wis",
                    "cha",
                  ] as const
                ).map((abbr, i) => {
                  const key = Object.keys(char.abilityScores)[i] as keyof typeof char.abilityScores;
                  return (
                    <div
                      key={abbr}
                      className="rounded bg-surface-800 py-1 text-center"
                    >
                      <p className="text-[10px] uppercase text-surface-500">
                        {abbr}
                      </p>
                      <p className="text-xs font-bold text-surface-200">
                        {char.abilityScores[key]}
                      </p>
                    </div>
                  );
                })}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

